\begin{align}
\text{Using } \left(x^n + 1\right) & = \left(x + 1\right)\left(x^{n-1} -x^{n-2} + x^{n-3} -x^{n-4} + \dots + 1\right) \text{ for all } \quad n \geq 1 \\
(x^9 + 1) & = \left(x + 1\right)\left(x^{8} -x^{7} + x^{6} - x^{5} + x^{4} -x^{3} + x^{2} -x + 1\right) \\
& \left(\frac{x^9 + 1}{x-1}\right) = \frac{\left(x+1\right)\left(x^{8} -x^{7} + x^{6} - x^{5} + x^{4} -x^{3} + x^{2} -x + 1\right)}{x-1} = x^8+x^{7}+x^{6}+x^{5}+x^{4}+x^{3}+x^{2}+x+1 \\
&  \text{Quoted from Wikipedia in the section on polynomial division} \\
&  \text{Leave comments if you see a problem with my reasoning or wording}
\end{align}
